    document.getElementById('createOfferForm').addEventListener('submit', async (e) => {
      e.preventDefault();
      await createOffer(false);
    });

    async function createOffer(sendImmediately) {
      const formData = {
        candidate_id: parseInt(document.getElementById('candidate_id').value),
        job_id: parseInt(document.getElementById('job_id').value),
        title: document.getElementById('title').value,
        salary: parseFloat(document.getElementById('salary').value),
        start_date: document.getElementById('start_date').value,
        benefits: document.getElementById('benefits').value
      };

      try {
        const res = await fetch('/api/onboarding/offers', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(formData)
        });

        if (!res.ok) throw new Error('Failed to create offer');

        const offer = await res.json();

        if (sendImmediately) {
          await sendOffer(offer.id);
        }

        closeCreateOfferModal();
        loadData();
      } catch (err) {
        console.error('Error creating offer:', err);
        alert('Failed to create offer. Please try again.');
      }
    }

    async function createAndSendOffer() {
      await createOffer(true);
    }

    async function sendOffer(offerId) {
      if (!confirm('Send this offer to the candidate?')) return;

      try {
        const res = await fetch(`/api/onboarding/offers/${offerId}/send`, {
          method: 'POST'
        });

        if (!res.ok) throw new Error('Failed to send offer');

        alert('Offer sent successfully!');
        loadData();
      } catch (err) {
        console.error('Error sending offer:', err);
        alert('Failed to send offer. Please try again.');
      }
    }

    loadData();
  </script>
</body>
</html>

